using UnityEngine;
namespace Packspire { public static class RuntimeBootstrap { [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)] static void Start(){var game=Object.FindFirstObjectByType<PackspireGame>();if(game==null)game=new GameObject("PackspireGame").AddComponent<PackspireGame>();if(Object.FindFirstObjectByType<PackspireUiFoundation>()==null)game.gameObject.AddComponent<PackspireUiFoundation>();if(Object.FindFirstObjectByType<Packspire2_5DPrototype>()==null)game.gameObject.AddComponent<Packspire2_5DPrototype>();} } }
